import React, { useState, useEffect } from 'react';
import { FormControl, InputLabel, MenuItem, Select } from '@material-ui/core';

function CategorySelect({
  selectedCategory,
  showExistingCategories,
  handleSelectChange,
  menuData,
  handleSubCategoryChange,
  selectedSubCategoryValues,
  existingCategories,
}) {
  // State för att hålla reda på de valda underkategorierna
  const [selectedSubCategories, setSelectedSubCategories] = useState([]);

  // Effekt för att uppdatera valda underkategorier när de ändras
  useEffect(() => {
    setSelectedSubCategories(selectedSubCategoryValues);
  }, [selectedSubCategoryValues]);

  return (
    <div>
      <FormControl className={classes.formControl}>
        {/* Dropdown för huvudkategorier */}
        <InputLabel id="category-label">Category</InputLabel>
        <Select
          labelId="category-label"
          value={selectedCategory}
          onChange={handleSelectChange}
          disabled={!showExistingCategories} // Inaktivera dropdown om det inte finns några existerande kategorier
        >
          {menuData.categories.map((category) => (
            <MenuItem key={category.mainMenu} value={category.mainMenu}>
              {category.mainMenu}
            </MenuItem>
          ))}
        </Select>
      </FormControl>

      {/* Dropdown för underkategorier */}
      <FormControl className={classes.formControl}>
        <InputLabel id="sub-category-label">Subcategory</InputLabel>
        <Select
          labelId="sub-category-label"
          multiple
          value={selectedSubCategories}
          onChange={handleSubCategoryChange}
          disabled={!showExistingCategories || !selectedCategory} // Inaktivera dropdown om det inte finns några existerande kategorier eller ingen huvudkategori är vald
        >
          {menuData.subCategories[selectedCategory]?.map((subCategory) => (
            <MenuItem key={subCategory} value={subCategory}>
              {subCategory}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
    </div>
  );
}

export default CategorySelect;
